exercise.solution_code:
#include <iostream>

int main()
{
    int tempSum{};

    {
        using std::cin;
        int t1{}, t2{}, t3{};
        cin >> t1 >> t2 >> t3;
        tempSum = t1 + t2 + t3;
    }

    int scoreSum{};

    {
        using std::cin;
        int s1{}, s2{};
        cin >> s1 >> s2;
        scoreSum = s1 + s2;
    }

    std::cout << "Avg temp: " << tempSum / 3 << " F\n";
    std::cout << "Avg score: " << scoreSum / 2 << '\n';

    return 0;
}
